import React, { useState, useEffect, useMemo } from 'react';
import { BrowserRouter, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import api from './api';

const TOKEN_KEY = 'token';
const ME_KEY = 'currentUser';

function useAuth() {
  const [user, setUser] = useState(() => {
    try {
      const raw = localStorage.getItem(ME_KEY);
      return raw ? JSON.parse(raw) : null;
    } catch (e) {
      return null;
    }
  });

  const login = (token, me) => {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(ME_KEY, JSON.stringify(me));
    setUser(me);
  };

  const logout = () => {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(ME_KEY);
    setUser(null);
  };

  const fetchMe = async () => {
    const token = localStorage.getItem(TOKEN_KEY);
    if (!token) return null;
    try {
      const response = await api.get('/auth/me');
      const me = response.data;
      localStorage.setItem(ME_KEY, JSON.stringify(me));
      setUser(me);
      return me;
    } catch (e) {
      logout();
      return null;
    }
  };

  return { user, login, logout, fetchMe };
}

function RequireAuth({ children, allowed }) {
  const { user, fetchMe } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    let cancelled = false;
    async function ensure() {
      let resolved = user;
      if (!resolved) {
        resolved = await fetchMe();
      }
      if (cancelled) return;
      if (!resolved) {
        navigate('/login', { replace: true });
      } else if (allowed && !allowed(resolved)) {
        navigate('/unauthorized', { replace: true });
      }
    }
    ensure();
    return () => { cancelled = true; };
  }, [user, navigate, allowed]);

  if (!user) return null;
  if (allowed && !allowed(user)) return null;
  return children;
}

export default function App() {
  const auth = useAuth();

  const routes = useMemo(() => {
    if (!auth.user) {
      return (
        <>
          <Route path="/" element={<Login login={auth.login} />} />
          <Route path="/login" element={<Login login={auth.login} />} />
          <Route path="/unauthorized" element={<Unauthorized />} />
          <Route path="*" element={<Navigate to="/login" replace />} />
        </>
      );
    }

    const role = (auth.user && auth.user.role) || 'customer';
    const roleRoutes = [];

    roleRoutes.push(
      <Route key="logout" path="/logout" element={<Logout logout={auth.logout} />} />,
      <Route key="unauthorized" path="/unauthorized" element={<Unauthorized />} />
    );

    if (role === 'admin' || role === 'employee') {
      roleRoutes.push(
        <Route key="new" path="/tickets/new" element={<CreateTicket user={auth.user} />} />
      );
      roleRoutes.push(
        <Route key="tickets" path="/tickets" element={<Tickets user={auth.user} />} />
      );
      roleRoutes.push(
        <Route key="ticket-detail" path="/tickets/:ticketId" element={<TicketDetail user={auth.user} />} />
      );
      roleRoutes.push(
        <Route key="dashboard" path="/dashboard" element={<Dashboard user={auth.user} />} />
      );

      let overviewLink = '/dashboard';
      let assignedLink = null;
      if (role === 'admin') {
        assignedLink = '/tickets';
      } else if (role === 'employee') {
        assignedLink = '/tickets';
      }

      roleRoutes.push(
        <Route key="fallback" path="*" element={<Navigate to={overviewLink} replace />} />
      );

      return roleRoutes;
    }

    if (role === 'customer') {
      roleRoutes.push(
        <Route key="my-tickets" path="/tickets" element={<Tickets user={auth.user} />} />,
        <Route key="create" path="/tickets/new" element={<CreateTicket user={auth.user} />} />,
        <Route key="ticket-detail" path="/tickets/:ticketId" element={<TicketDetail user={auth.user} />} />,
        <Route key="home" path="/" element={<Home user={auth.user} />} />
      );

      roleRoutes.push(
        <Route key="fallback" path="*" element={<Navigate to="/tickets" replace />} />
      );

      return roleRoutes;
    }

    return (
      <>
        <Route path="*" element={<Navigate to="/" replace />} />
      </>
    );
  }, [auth.user, auth.login, auth.logout]);

  const isAuthed = !!auth.user;

  return (
    <BrowserRouter>
      {isAuthed && <Navbar user={auth.user} onLogout={auth.logout} />}
      <Routes>
        {routes}
      </Routes>
    </BrowserRouter>
  );
}

function Logout({ logout }) {
  useEffect(() => {
    logout();
  }, [logout]);
  return <Navigate to="/login" replace />;
}

function Unauthorized() {
  return (
    <div style={{ padding: 24 }}>
      <h1>Unauthorized</h1>
      <p>You do not have access to this page. Please contact support or request access.</p>
    </div>
  );
}
